mcqs.question:
What is the output of the following code?
template<typename T>
T max(T a, T b) { return (a > b) ? a : b; }
int main() { std::cout << max(3, 7); }

What is the output?
template<typename T>
void print(T x) { std::cout << x; }
void print(int x) { std::cout << x+1; }
int main() { print(5); }
